async #toViemContracts<
    ModuleIdT extends string,
    ContractNameT extends string,
    IgnitionModuleResultsT extends IgnitionModuleResult<ContractNameT>,
  >(
    connection: NetworkConnection<ChainTypeT>,
    ignitionModule: IgnitionModule<
      ModuleIdT,
      ContractNameT,
      IgnitionModuleResultsT
    >,
    result: SuccessfulDeploymentResult,
  ): Promise<
    IgnitionModuleResultsToViemContracts<ContractNameT, IgnitionModuleResultsT>
  > {
    return Object.fromEntries(
      await Promise.all(
        Object.entries(ignitionModule.results).map(
          async ([name, contractFuture]) => [
            name,
            await this.#getContract(
              connection,
              contractFuture,
              result.contracts[contractFuture.id],
            ),
          ],
        ),
      ),
    );
  }

async #convertContractFutureToViemContract(
  connection: NetworkConnection<ChainTypeT>,
  future: ContractFuture<string>,
  deployedContract: { address: string },
) {
  switch (future.type) {
    case FutureType.NAMED_ARTIFACT_CONTRACT_DEPLOYMENT:
    case FutureType.NAMED_ARTIFACT_LIBRARY_DEPLOYMENT:
    case FutureType.NAMED_ARTIFACT_CONTRACT_AT:
      return await this.#convertHardhatContractToViemContract(
        connection,
        future,
        deployedContract,
      );
    case FutureType.CONTRACT_DEPLOYMENT:
    case FutureType.LIBRARY_DEPLOYMENT:
    case FutureType.CONTRACT_AT:
      return await this.#convertArtifactToViemContract(
        connection,
        future,
        deployedContract,
      );
  }
}

taskTransactions: NewTaskActionFunction<TrackTxArguments> = async (
  { txHash, deploymentId },
  hre: HardhatRuntimeEnvironment,
) => {
  const deploymentDir = path.join(
    hre.config.paths.ignition,
    "deployments",
    deploymentId,
  );

  await verifyArtifactsVersion(deploymentDir);

  const connection = await hre.network.create();

  const output = await trackTransaction(
    deploymentDir,
    txHash,
    connection.provider,
    hre.config.ignition.requiredConfirmations,
  );

  console.log(
    output ??
      `Thanks for providing the transaction hash, your deployment has been fixed.

Now you can re-run Hardhat Ignition to continue with your deployment.`,
  );
}

