public async compileBuildInfo(
  buildInfo: SolidityBuildInfo,
  options?: CompileBuildInfoOptions,
): Promise<CompilerOutput> {
  const quiet = options?.quiet ?? false;

  // Build info recompilation is always solc-only: build info files are
  // produced by solc and must be recompiled with the same solc version.
  // We bypass both downloadCompilers and getCompiler hooks — this is a
  // self-contained solc replay path, not plugin-configurable compilation.
  await downloadSolcCompilers(new Set([buildInfo.solcVersion]), quiet);

  const compiler = await getCompiler(buildInfo.solcVersion, {
    preferWasm: false,
  });

  return await compiler.compile(buildInfo.input);
}

function formatProjectRootResolutionError(
  error: ProjectRootResolutionError,
): string {
  switch (error.type) {
    case RootResolutionErrorType.PROJECT_ROOT_FILE_NOT_IN_PROJECT: {
      return `The file is not inside your Hardhat project.`;
    }

    case RootResolutionErrorType.PROJECT_ROOT_FILE_DOES_NOT_EXIST: {
      return "The file doesn't exist";
    }

    case RootResolutionErrorType.PROJECT_ROOT_FILE_IN_NODE_MODULES: {
      // TODO: This should have a link to the docs.
      return `The file is inside your node_modules directory.

Please read Hardhat's documentation to learn how to compile npm files.`;
    }
  }
}

public static async create(
  projectRootPath: string,
  remappingsReader: RemappingsReaderFunction = (
    packageName,
    packageVersion,
    packagePath,
    defaultBehavior,
  ) => defaultBehavior(packageName, packageVersion, packagePath),
): Promise<RemappedNpmPackagesGraphImplementation> {
  const projectPackageJson = await readJsonFile<PackageJson>(
    path.join(projectRootPath, "package.json"),
  );

  const resolvedNpmPackage: ResolvedNpmPackage = {
    name: projectPackageJson.name,
    version: projectPackageJson.version,
    exports: projectPackageJson.exports,
    rootFsPath: projectRootPath,
    inputSourceNameRoot: HARDHAT_PROJECT_INPUT_SOURCE_NAME_ROOT,
  };

  return new RemappedNpmPackagesGraphImplementation(
    resolvedNpmPackage,
    remappingsReader,
  );
}

async function isTelemetryEnabled(
  telemetryConfigFilePath?: string,
): Promise<boolean> {
  telemetryConfigFilePath ??= await getTelemetryConfigFilePath();

  log(`Looking for telemetry config file at ${telemetryConfigFilePath}`);

  if (await exists(telemetryConfigFilePath)) {
    // Telemetry enabled value was explicitly set, hence return the answer
    const { enabled } = await readJsonFile<TelemetryConfig>(
      telemetryConfigFilePath,
    );
    log(`Telemetry enabled value: ${enabled}`);

    return enabled;
  }

  log("No telemetry config file found, assuming telemetry is enabled");

  return true;
}

async function getOrCreateGlobalHardhatRuntimeEnvironment(): Promise<HardhatRuntimeEnvironment> {
  let globalHre = getGlobalHardhatRuntimeEnvironment();

  if (globalHre !== undefined) {
    return globalHre;
  }

  const configPath = await resolveHardhatConfigPath();
  const projectRoot = await resolveProjectRoot(configPath);
  const userConfig = await importUserConfig(configPath);

  globalHre = await createHardhatRuntimeEnvironment(
    userConfig,
    { config: configPath },
    projectRoot,
  );

  setGlobalHardhatRuntimeEnvironment(globalHre);

  return globalHre;
}

private static _getSerializedModulesInReverseTopologicalOrder(
  serializedIgnitionModule: SerializedIgnitionModule,
): SerializedModuleDescription[] {
  const graph: Graph<SerializedModuleDescription> = new Map();

  for (const mod of Object.values(serializedIgnitionModule.modules)) {
    graph.set(mod, new Set());
  }

  for (const mod of Object.values(serializedIgnitionModule.modules)) {
    for (const submodToken of mod.submodules) {
      const submod = serializedIgnitionModule.modules[submodToken.moduleId];
      graph.get(submod)!.add(mod);
    }
  }

  return getNodesInTopologicalOrder(graph);
}

constructor(
  private readonly _config: DeployConfig,
  private readonly _deploymentDir: string | undefined,
  private readonly _executionStrategy: ExecutionStrategy,
  private readonly _jsonRpcClient: JsonRpcClient,
  private readonly _artifactResolver: ArtifactResolver,
  private readonly _deploymentLoader: DeploymentLoader,
  private readonly _executionEventListener?:
    | ExecutionEventListener
    | undefined,
) {
  assertIgnitionInvariant(
    this._config.requiredConfirmations >= 1,
    `Configured value 'requiredConfirmations' cannot be less than 1. Value given: '${this._config.requiredConfirmations}'`,
  );
}

constructor(
  private readonly _deploymentDirPath: string,
  private readonly _executionEventListener?:
    | ExecutionEventListener
    | undefined,
) {
  const artifactsDir = path.join(this._deploymentDirPath, "artifacts");
  const buildInfoDir = path.join(this._deploymentDirPath, "build-info");
  const journalPath = path.join(this._deploymentDirPath, "journal.jsonl");
  const deployedAddressesPath = path.join(
    this._deploymentDirPath,
    "deployed_addresses.json",
  );

  this._journal = new FileJournal(journalPath, this._executionEventListener);

  this._paths = {
    deploymentDir: this._deploymentDirPath,
    artifactsDir,
    buildInfoDir,
    journalPath,
    deployedAddressesPath,
  };

  this._deploymentDirsEnsured = false;
}

function decodeArtifactFunctionCallResult(
  artifact: Artifact,
  functionName: string,
  returnData: string,
): InvalidResultError | SuccessfulEvmExecutionResult {
  const validationErrors = validateArtifactFunctionName(artifact, functionName);

  if (validationErrors.length > 0) {
    throw validationErrors[0];
  }

  const iface = ethers.Interface.from(artifact.abi);
  const functionFragment = getFunctionFragment(iface, functionName);

  try {
    const decoded = iface.decodeFunctionResult(functionFragment, returnData);
    const values = ethersResultIntoEvmTuple(decoded, functionFragment.outputs);

    return { type: EvmExecutionResultTypes.SUCCESSFUL_RESULT, values };
  } catch {
    return {
      type: EvmExecutionResultTypes.INVALID_RESULT_ERROR,
      data: returnData,
    };
  }
}

private async _syncNonces(
  deploymentState: DeploymentState,
  ignitionModule: IgnitionModule<
    string,
    string,
    IgnitionModuleResult<string>
  >,
  accounts: string[],
  defaultSender: string,
): Promise<DeploymentState> {
  const nonceSyncMessages = await getNonceSyncMessages(
    this._jsonRpcClient,
    deploymentState,
    ignitionModule,
    accounts,
    defaultSender,
    this._requiredConfirmations,
  );

  for (const message of nonceSyncMessages) {
    deploymentState = await applyNewMessage(
      message,
      deploymentState,
      this._deploymentLoader,
    );
  }

  return deploymentState;
}

async function _storeArtifactAndBuildInfoAgainstDeployment(
  future:
    | NamedArtifactLibraryDeploymentFuture<string>
    | NamedArtifactContractDeploymentFuture<string>
    | NamedArtifactContractAtFuture<string>,
  {
    deploymentLoader,
    artifactResolver,
  }: {
    deploymentLoader: DeploymentLoader;
    artifactResolver: ArtifactResolver;
  },
): Promise<void> {
  const artifact = await artifactResolver.loadArtifact(future.contractName);
  await deploymentLoader.storeNamedArtifact(
    future.id,
    future.contractName,
    artifact,
  );
  const buildInfo = await artifactResolver.getBuildInfo(future.contractName);

  if (buildInfo !== undefined) {
    await deploymentLoader.storeBuildInfo(future.id, buildInfo);
  }
}

function initialiseDeploymentExecutionStateFrom(
  action: DeploymentExecutionStateInitializeMessage,
): DeploymentExecutionState {
  const deploymentExecutionInitialState: DeploymentExecutionState = {
    id: action.futureId,
    type: ExecutionSateType.DEPLOYMENT_EXECUTION_STATE,
    futureType: action.futureType,
    strategy: action.strategy,
    strategyConfig: action.strategyConfig,
    status: ExecutionStatus.STARTED,
    dependencies: new Set<string>(action.dependencies),
    artifactId: action.artifactId,
    contractName: action.contractName,
    constructorArgs: action.constructorArgs,
    libraries: action.libraries,
    value: action.value,
    from: action.from,
    networkInteractions: [],
  };

  return deploymentExecutionInitialState;
}
